module top_module(
    output X,
    input  A,
    input  B,
    input  C,
    input  D
);// Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    wire unused_AB, CD, ABCD;

    // Modified to use a simple XOR operation instead
    assign unused_AB = A ^ B;
    assign CD = C ^ D;
    assign ABCD = unused_AB ^ CD;

    assign X = ABCD;

endmodule
